"use client";

import { useState, useRef, useEffect } from "react";

const API = "http://localhost:4001/api/qcore";
const WS_URL = "ws://localhost:4001/ws/qcore";
const USER_ID = "test-user-1";

interface Message {
  role: string;
  content: string;
}

interface Chat {
  id: string;
  title: string;
  updatedAt: string;
}

export default function QCorePage() {
  const [chats, setChats] = useState<Chat[]>([]);
  const [activeChatId, setActiveChatId] = useState<string | null>(null);
  const [messages, setMessages] = useState<Message[]>([]);
  const [input, setInput] = useState("");
  const [streaming, setStreaming] = useState(false);
  const [streamText, setStreamText] = useState("");
  const wsRef = useRef<WebSocket | null>(null);
  const bottomRef = useRef<HTMLDivElement>(null);

  useEffect(() => { loadChats(); }, []);
  useEffect(() => { bottomRef.current?.scrollIntoView({ behavior: "smooth" }); }, [messages, streamText]);

  async function loadChats() {
    const res = await fetch(`${API}/chats`, { headers: { "x-user-id": USER_ID } });
    const data = await res.json();
    setChats(data);
  }

  async function loadMessages(chatId: string) {
    const res = await fetch(`${API}/chats/${chatId}/messages`, { headers: { "x-user-id": USER_ID } });
    const data = await res.json();
    setMessages(data);
    setActiveChatId(chatId);
  }

  async function createChat() {
    const res = await fetch(`${API}/chats`, {
      method: "POST",
      headers: { "x-user-id": USER_ID, "Content-Type": "application/json" },
      body: JSON.stringify({ title: "New Chat" }),
    });
    const chat = await res.json();
    setChats((prev) => [chat, ...prev]);
    setActiveChatId(chat.id);
    setMessages([]);
  }

  function connectWS(): Promise<WebSocket> {
    return new Promise((resolve) => {
      if (wsRef.current && wsRef.current.readyState === WebSocket.OPEN) {
        resolve(wsRef.current);
        return;
      }
      const ws = new WebSocket(WS_URL);
      ws.onopen = () => {
        ws.send(JSON.stringify({ type: "auth", userId: USER_ID }));
        wsRef.current = ws;
        setTimeout(() => resolve(ws), 100);
      };
      ws.onclose = () => { wsRef.current = null; };
    });
  }

  async function sendMessage() {
    if (!input.trim() || !activeChatId || streaming) return;
    const userMsg = input.trim();
    setInput("");
    setMessages((prev) => [...prev, { role: "user", content: userMsg }]);
    setStreaming(true);
    setStreamText("");

    const ws = await connectWS();
    const handler = (event: MessageEvent) => {
      const data = JSON.parse(event.data);
      if (data.type === "chunk") {
        setStreamText((prev) => prev + data.text);
      }
      if (data.type === "stream_end") {
        setMessages((prev) => [...prev, { role: "assistant", content: data.content }]);
        setStreamText("");
        setStreaming(false);
        ws.removeEventListener("message", handler);
        loadChats();
      }
      if (data.type === "error") {
        setStreamText("");
        setStreaming(false);
        setMessages((prev) => [...prev, { role: "assistant", content: "Error: " + data.message }]);
        ws.removeEventListener("message", handler);
      }
    };
    ws.addEventListener("message", handler);
    ws.send(JSON.stringify({ type: "message", chatId: activeChatId, content: userMsg }));
  }

  async function deleteChat(chatId: string) {
    await fetch(`${API}/chats/${chatId}`, { method: "DELETE", headers: { "x-user-id": USER_ID } });
    setChats((prev) => prev.filter((c) => c.id !== chatId));
    if (activeChatId === chatId) { setActiveChatId(null); setMessages([]); }
  }

  return (
    <div className="flex h-screen bg-gray-950 text-white">
      {/* Sidebar */}
      <div className="w-72 bg-gray-900 border-r border-gray-800 flex flex-col">
        <div className="p-4 border-b border-gray-800">
          <button onClick={createChat} className="w-full py-2 px-4 bg-indigo-600 hover:bg-indigo-500 rounded-lg font-medium transition">
            + New Chat
          </button>
        </div>
        <div className="flex-1 overflow-y-auto">
          {chats.map((chat) => (
            <div
              key={chat.id}
              className={`flex items-center justify-between px-4 py-3 cursor-pointer hover:bg-gray-800 transition ${activeChatId === chat.id ? "bg-gray-800" : ""}`}
              onClick={() => loadMessages(chat.id)}
            >
              <span className="truncate text-sm flex-1">{chat.title}</span>
              <button
                onClick={(e) => { e.stopPropagation(); deleteChat(chat.id); }}
                className="ml-2 text-gray-500 hover:text-red-400 text-xs"
              >
                ✕
              </button>
            </div>
          ))}
        </div>
        <div className="p-4 border-t border-gray-800 text-center text-xs text-gray-500">
          QCoreAI · AEVION Platform
        </div>
      </div>

      {/* Main */}
      <div className="flex-1 flex flex-col">
        {!activeChatId ? (
          <div className="flex-1 flex items-center justify-center">
            <div className="text-center">
              <h1 className="text-4xl font-bold mb-2 bg-gradient-to-r from-indigo-400 to-purple-400 bg-clip-text text-transparent">
                QCoreAI
              </h1>
              <p className="text-gray-400">Create a new chat to start</p>
            </div>
          </div>
        ) : (
          <>
            {/* Messages */}
            <div className="flex-1 overflow-y-auto px-4 py-6 space-y-4">
              {messages.map((msg, i) => (
                <div key={i} className={`flex ${msg.role === "user" ? "justify-end" : "justify-start"}`}>
                  <div className={`max-w-2xl px-4 py-3 rounded-2xl text-sm leading-relaxed whitespace-pre-wrap ${
                    msg.role === "user"
                      ? "bg-indigo-600 text-white"
                      : "bg-gray-800 text-gray-100"
                  }`}>
                    {msg.content}
                  </div>
                </div>
              ))}
              {streaming && streamText && (
                <div className="flex justify-start">
                  <div className="max-w-2xl px-4 py-3 rounded-2xl text-sm leading-relaxed whitespace-pre-wrap bg-gray-800 text-gray-100">
                    {streamText}
                    <span className="animate-pulse ml-1">▊</span>
                  </div>
                </div>
              )}
              <div ref={bottomRef} />
            </div>

            {/* Input */}
            <div className="border-t border-gray-800 p-4">
              <div className="max-w-3xl mx-auto flex gap-3">
                <input
                  value={input}
                  onChange={(e) => setInput(e.target.value)}
                  onKeyDown={(e) => { if (e.key === "Enter" && !e.shiftKey) { e.preventDefault(); sendMessage(); } }}
                  placeholder="Type a message..."
                  disabled={streaming}
                  className="flex-1 bg-gray-800 border border-gray-700 rounded-xl px-4 py-3 text-sm focus:outline-none focus:ring-2 focus:ring-indigo-500 disabled:opacity-50"
                />
                <button
                  onClick={sendMessage}
                  disabled={streaming || !input.trim()}
                  className="px-6 py-3 bg-indigo-600 hover:bg-indigo-500 disabled:opacity-50 disabled:hover:bg-indigo-600 rounded-xl font-medium text-sm transition"
                >
                  {streaming ? "..." : "Send"}
                </button>
              </div>
            </div>
          </>
        )}
      </div>
    </div>
  );
}